<section class="section invoice-page"><div class="container container--narrow"><div class="invoice-sheet">
    <div class="invoice-head"><div><span class="eyebrow">Tax Invoice</span><h1><?= e($order['invoice_number']) ?></h1><p><?= e(substr((string)$order['invoice_date'],0,10)) ?></p></div><button class="btn btn-outline no-print" onclick="window.print()">Print invoice</button></div>
    <div class="invoice-parties"><div><strong>Supplier</strong><p><?= e($order['supplier']['trade_name']??$settings['gst_trade_name']??'') ?><br><?= e($order['supplier']['legal_name']??$settings['gst_legal_name']??'') ?><br>GSTIN: <?= e($order['supplier']['gstin']??$settings['gstin']??'') ?><br><?= nl2br(e($order['supplier']['address']??$settings['gst_address']??'')) ?></p></div><div><strong>Bill / Ship To</strong><p><?= e($order['customer_name']??'') ?><br><?= e($order['shipping_address']??'') ?><br><?= e(($order['shipping_city']??'').' '.($order['shipping_pincode']??'')) ?><br><?= e($order['shipping_state']??'') ?><?php if(!empty($order['customer_gstin'])): ?><br>GSTIN: <?= e($order['customer_gstin']) ?><?php endif; ?></p></div></div>
    <p><strong>Place of supply:</strong> <?= e($order['place_of_supply']??'') ?> · <?= e(ucfirst($order['supply_type']??'')) ?></p>
    <div class="table-wrap"><table><thead><tr><th>Product</th><th>HSN</th><th>Qty</th><th>Taxable</th><th>Rate</th><th>CGST</th><th>SGST</th><th>IGST</th><th>Total</th></tr></thead><tbody><?php foreach(($order['tax_lines']??[]) as $line): ?><tr><td><?= e($line['name']??'') ?></td><td><?= e($line['hsn_code']??'') ?></td><td><?= e((string)($line['qty']??1)) ?></td><td>₹<?= e(number_format((float)($line['taxable_value']??0),2)) ?></td><td><?= e((string)($line['gst_rate']??0)) ?>%</td><td>₹<?= e(number_format((float)($line['cgst']??0),2)) ?></td><td>₹<?= e(number_format((float)($line['sgst']??0),2)) ?></td><td>₹<?= e(number_format((float)($line['igst']??0),2)) ?></td><td>₹<?= e(number_format((float)($line['gross_value']??0),2)) ?></td></tr><?php endforeach; ?></tbody></table></div>
    <div class="invoice-totals"><p>Taxable value <strong>₹<?= e(number_format((float)($order['taxable_value']??0),2)) ?></strong></p><p>Total GST <strong>₹<?= e(number_format((float)($order['tax_total']??0),2)) ?></strong></p><p>Invoice total <strong>₹<?= e(number_format((float)($order['total']??0),2)) ?></strong></p><small>Product prices are GST-inclusive. This invoice does not include consultant appointment services.</small></div>
</div></div></section>
